oxy_webhelp_navlinks = {"azr_devops_set_up_backup_loc-d27248e32002":{"topics":[{"title":"Evaluate backup options for Azure DevOps","shortdesc":"<p class=\"shortdesc\">It is important to evaluate the backup options for Azure DevOps to align with the         performance and data retrieval needs. Key considerations include backup location, access         tiers, endpoint usage, and encryption standards.<\/p>","href":"azure_devops\/azr_devops_evaluate_backup_options.html","attributes":{"data-id":"azr_devops_evaluate_backup_options"},"menu":{"hasChildren":false},"tocID":"azr_devops_evaluate_backup_options-d27248e32015","next":"azr_devops_evaluate_backup_options-d27248e32015"},{"title":"User permissions for Azure DevOps backup location","shortdesc":"<p class=\"shortdesc\">To set up Azure DevOps backup location in <span class=\"ph\">RSC<\/span>, the <span class=\"ph\">RSC<\/span> user must be assigned a role with specific permissions.<\/p>","href":"azure_devops\/azr_devops_user_perms_backup_loc.html","attributes":{"data-id":"azr_devops_user_perms_backup_loc"},"menu":{"hasChildren":false},"tocID":"azr_devops_user_perms_backup_loc-d27248e32061","topics":[]},{"title":"Configure Azure DevOps backup location","shortdesc":"<p class=\"shortdesc\">You must create a backup location for storing the snapshots of Azure DevOps         organizations, projects, and repositories. Additionally, you can configure a private or         service endpoint to back up snapshots to the backup location.<\/p>","href":"azure_devops\/azr_devops_configure_backup_loc.html","attributes":{"data-id":"azr_devops_configure_backup_loc"},"menu":{"hasChildren":false},"tocID":"azr_devops_configure_backup_loc-d27248e32078","next":"azr_devops_configure_backup_loc-d27248e32078"}]}};